package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() throws IOException {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrint_nullValue_nullStringIsNull() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        when(format.getNullString()).thenReturn(null);

        // Spy on printer to intercept private method calls
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.print(null);

        // Verify that format.getNullString() is called
        verify(format).getNullString();

        // Since verifyNoInteractions is not available, verify that out.append is never called with null
        // and no calls with null argument
        verify(out, never()).append((CharSequence) isNull());
    }

    @Test
    void testPrint_nullValue_nullStringIsNonNull() throws IOException {
        when(format.getNullString()).thenReturn("NULL");

        CSVPrinter spyPrinter = Mockito.spy(new CSVPrinter(out, format));
        spyPrinter.print(null);

        // Verify format.getNullString() called
        verify(format).getNullString();

        // Verify that out.append is called with "NULL" somewhere inside print
        // Since out is mocked Appendable, verify append called with "NULL"
        try {
            verify(out, atLeastOnce()).append("NULL");
        } catch (IOException e) {
            fail("IOException thrown during verification: " + e.getMessage());
        }
    }

    @Test
    void testPrint_nonNullValue() throws IOException {
        String value = "testValue";
        CSVPrinter spyPrinter = Mockito.spy(new CSVPrinter(out, format));
        spyPrinter.print(value);

        // Verify that out.append is called with value.toString()
        try {
            verify(out, atLeastOnce()).append(value);
        } catch (IOException e) {
            fail("IOException thrown during verification: " + e.getMessage());
        }
    }

}
